<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &#39;child_process&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;rollup-plugin-node-polyfills/polyfills/empty&#39;</span></span>
